  1	import * as React from 'react';
  2	import { Tooltip } from '@patternfly/react-core';
  3	import { useHover } from '@patternfly/react-topology';
  4	import classnames from 'classnames';
  5	import * as _ from 'lodash';
  6	import { useTranslation } from 'react-i18next';
  7	
  8	import { BUILDER_NODE_ADD_RADIUS } from './const';
  9	import RemoveNodeDecorator from './RemoveNodeDecorator';
 10	import { KebabOption, NewTaskNodeCallback } from './types';
 11	import { TaskKind } from '../../types';
 12	import { getReferenceForModel } from '../pipelines-overview/utils';
 13	import { getResourceModelFromTaskKind, getTaskName } from '../utils/pipeline-augment';
 14	import { ResourceIcon } from '@openshift-console/dynamic-plugin-sdk';
 15	import { truncateMiddle } from './truncate-middle';
 16	
 17	type KeyedKebabOption = KebabOption & { key: string };
 18	
 19	const taskToOption = (
 20	  task: TaskKind,
 21	  callback: NewTaskNodeCallback,
 22	): KeyedKebabOption => {
 23	  const { kind } = task;
 24	  const name = getTaskName(task)
 25	
 26	  return {
 27	    key: `${name}-${kind}`,
 28	    label: name,
 29	    icon: (
 30	      <ResourceIcon
 31	        kind={getReferenceForModel(getResourceModelFromTaskKind(kind))}
 32	      />
 33	    ),
 34	    callback: () => {
 35	      callback(task);
 36	    },
 37	  };
 38	};
 39	
 40	const TaskList: React.FC<any> = ({
 41	  width,
 42	  height,
 43	  listOptions,
 44	  unselectedText,
 45	  onRemoveTask,
 46	  onNewTask,
 47	  onTaskSearch,
 48	}) => {
 49	  const { t } = useTranslation('plugin__pipelines-console-plugin');
 50	  const triggerRef = React.useRef(null);
 51	  const textRef = React.useRef();
 52	  const [hover, hoverRef] = useHover();
 53	
 54	  const options = _.sortBy(
 55	    listOptions.map((task) => taskToOption(task, onNewTask)),
 56	    (o) => o.label,
 57	  );
 58	  const unselectedTaskText = unselectedText || t('Add task');
 59	
 60	  const truncatedTaskText = React.useMemo(
 61	    () =>
 62	      truncateMiddle(unselectedTaskText, {
 63	        length: 10,
 64	        truncateEnd: true,
 65	      }),
 66	    [unselectedTaskText],
 67	  );
 68	  const renderText = (
 69	    <text
 70	      x={width / 2}
 71	      y={height / 2 + 1}
 72	      className="odc-task-list-node__render-text"
 73	      ref={textRef}
 74	    >
 75	      {truncatedTaskText}
 76	    </text>
 77	  );
 78	
 79	  return (
 80	    <>
 81	      <g
 82	        data-test="task-list"
 83	        ref={hoverRef}
 84	        className="odc-task-list-node__trigger"
 85	        onClick={(e) => {
 86	          e.stopPropagation();
 87	          onTaskSearch(onNewTask);
 88	        }}
 89	      >
 90	        <rect
 91	          ref={triggerRef}
 92	          className={classnames('odc-task-list-node__trigger-background', {
 93	            'is-disabled': options.length === 0,
 94	          })}
 95	          width={width}
 96	          height={height}
 97	        />
 98	        {options.length === 0 ? (
 99	          <text
100	            className="odc-task-list-node__trigger-disabled"
101	            x={width / 2}
102	            y={height / 2 + 1}
103	          >
104	            {t('No tasks')}
105	          </text>
106	        ) : (
107	          <g>
108	            <rect
109	              className={
110	                hover
111	                  ? 'odc-task-list-node__trigger-underline--hover'
112	                  : 'odc-task-list-node__trigger-underline'
113	              }
114	              y={height}
115	              width={width}
116	              height={hover ? 2 : 1}
117	            />
118	
119	            {onRemoveTask && hover && (
120	              <g>
121	                <RemoveNodeDecorator
122	                  removeCallback={onRemoveTask}
123	                  x={120}
124	                  y={BUILDER_NODE_ADD_RADIUS / 4}
125	                  content={t('Delete task')}
126	                />
127	              </g>
128	            )}
129	            {unselectedTaskText !== truncatedTaskText ? (
130	              <Tooltip content={unselectedTaskText} triggerRef={textRef}>
131	                {renderText}
132	              </Tooltip>
133	            ) : (
134	              renderText
135	            )}
136	          </g>
137	        )}
138	      </g>
139	    </>
140	  );
141	};
142	export default TaskList;

